{
  "name": "DataForge",
  "language": "Python",
  "package_manager": "pip",
  "prerequisites": ["Python 3.9+", "pip 22+", "Git"],
  "setup_steps": [
    {"step": "Clone the repository", "command": "git clone https://github.com/example/dataforge.git", "explanation": "Downloads the source code to your machine."},
    {"step": "Install dependencies", "command": "cd dataforge && pip install -e .", "explanation": "Installs DataForge and its dependencies in editable mode."},
    {"step": "Verify installation", "command": "dataforge --version", "explanation": "Should print the current version number."},
    {"step": "Run tests", "command": "pytest tests/", "explanation": "Ensures everything is working correctly."}
  ],
  "examples": [
    {"title": "Load a CSV file", "code": "from dataforge import load\ndf = load('data.csv')\nprint(df.shape)", "output": "(1000, 5)"},
    {"title": "Apply transformations", "code": "df = df.transform([\n    {'op': 'filter', 'col': 'age', 'gt': 18},\n    {'op': 'sort', 'col': 'name'}\n])\nprint(len(df))", "output": "750"}
  ],
  "faq": [
    {"q": "ImportError: No module named dataforge", "a": "Make sure you ran pip install -e . from the project root directory."},
    {"q": "Tests fail with connection error", "a": "Some integration tests require a running PostgreSQL instance. Run pytest tests/unit/ for unit tests only."},
    {"q": "How do I upgrade?", "a": "Run git pull && pip install -e . to get the latest version."}
  ]
}

